package org.eclipse.rdf4j.sail.multirepo;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.function.Function;

import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.common.iteration.Iterations;
import org.junit.jupiter.api.Test;

class MultiUnionIterationTest {

	@Test
	void dedupesAcrossMembersWhilePreservingUnionOrder() {
		TrackingIteration left = new TrackingIteration("left-only", "shared");
		TrackingIteration right = new TrackingIteration("shared", "right-only", "shared");

		MultiUnionIteration<String, String> iteration = new MultiUnionIteration<>(List.of(left, right),
				Function.identity());

		assertThat(Iterations.asList(iteration)).containsExactly("left-only", "shared", "right-only");
		assertThat(left.wasClosed()).isTrue();
		assertThat(right.wasClosed()).isTrue();
	}

	@Test
	void closeAlsoClosesRemainingMemberIterations() {
		TrackingIteration left = new TrackingIteration("left-only", "shared");
		TrackingIteration right = new TrackingIteration("shared", "right-only");

		MultiUnionIteration<String, String> iteration = new MultiUnionIteration<>(List.of(left, right),
				Function.identity());

		assertThat(iteration.hasNext()).isTrue();
		assertThat(iteration.next()).isEqualTo("left-only");

		iteration.close();

		assertThat(left.wasClosed()).isTrue();
		assertThat(right.wasClosed()).isTrue();
	}

	private static final class TrackingIteration extends CloseableIteratorIteration<String> {

		private boolean closed;

		private TrackingIteration(String... values) {
			super(List.of(values).iterator());
		}

		@Override
		protected void handleClose() {
			closed = true;
		}

		private boolean wasClosed() {
			return closed;
		}
	}
}
